40	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[]; previousQuoteCount?: number }): number {
41	  const items = input.items;
42	  const countByType: Record<string, number> = {};
43	  for (const item of items) {
44	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
45	  }
46	  let basePrice = 0;
47	  for (const type of Object.keys(countByType)) {
48	    const count = countByType[type];
49	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
50	    if (formsRuneBlock) {
51	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
52	    } else {
53	      basePrice += count * BASE_PRICE_BY_TYPE[type];
54	    }
55	  }
56	  let highEnchantmentSurcharges = 0;
57	  let cursedSurcharges = 0;
58	  for (const item of items) {
59	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
60	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
61	    }
62	    if (item.cursed === true) {
63	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
64	    }
65	  }
66	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
67	  const qualifiesForLoyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
68	  const loyaltyDiscount = qualifiesForLoyaltyDiscount ? basePrice * LOYALTY_DISCOUNT_RATE : 0;
69	  const qualifiesForFollowUpDiscount = (input.previousQuoteCount ?? 0) >= FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES;
70	  const followUpDiscount = qualifiesForFollowUpDiscount ? basePrice * FOLLOWUP_DISCOUNT_RATE : 0;
71	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
72	  return Math.ceil(premium);
73	}
